B.Y8=s(["\u0110\u1eebng v\u1ed9i m\u1eebng, ta v\u1eabn ch\u01b0a g\u1ee5c.","M\xe1u ta xu\u1ed1ng th\u1ea5p r\u1ed3i... nh\u01b0ng tr\u1eadn ch\u01b0a xong.","Ch\u1ec9 thi\u1ebfu ch\xfat n\u1eefa th\xf4i, nh\u01b0ng ng\u01b0\u01a1i v\u1eabn ph\u1ea3i tr\u1ea3 gi\xe1.","30 ch\u01b0a ph\u1ea3i l\xe0 t\u1ebft, nh\u01b0ng ng\u01b0\u01a1i v\u1eabn ph\u1ea3i tr\u1ea3 gi\xe1.","Ta s\u1ebd l\u1eadt k\xe8o",u.y,"Ch\u1ec9 1 ch\xfat sinh l\u1ef1c nh\u01b0ng v\u1eabn \u0111\u1ee7 h\u1ea1 ng\u01b0\u01a1i.","T\u01b0\u1edfng tao s\u1eafp ch\u1ebft h\u1ea3? C\xf2n l\xe2u!","HP \u0111\u1ecf l\xe8 nh\u01b0ng v\u1eabn \u0111\u1ee7 \u0111\u1ea5m m\xe0y.","Ch\u01b0a n\u1eb1m \u0111\xe2u, \u0111\u1eebng m\u1eebng s\u1edbm.","C\xf2n th\u1edf l\xe0 c\xf2n g\u1ee1 \u0111\u01b0\u1ee3c.","G\u1ea7n ch\u1ebft r\u1ed3i... nh\u01b0ng ch\u01b0a t\u1edbi l\u01b0\u1ee3t tao thua.","\u0110\u1eebng c\xf3 ch\u1ee7 quan, sai l\u1ea7m \u0111\xf3.","M\u1ed9t hit n\u1eefa th\xf4i l\xe0 m\xe0y \u0111i tr\u01b0\u1edbc.","Tao y\u1ebfu nh\u01b0ng tao l\xec.","C\xf2n t\xed m\xe1u nh\u01b0ng damage v\u1eabn \u0111\u1ee7 \u0111au.","Tao m\xe0 s\u1ed1ng l\u1ea1i l\xe0 m\xe0y m\u1ec7t.","Khoan \u0103n m\u1eebng, coi ch\u1eebng \u0103n ng\u01b0\u1ee3c.","L\u1eadt k\xe8o trong t\xedch t\u1eafc th\xf4i.","Tao c\xf2n b\xe0i ch\u01b0a x\xe0i \u0111\xe2u.","Ch\u01b0a tung h\u1ebft skill \u0111\xe2u nha.","\u0110\u1ee3i \u0111\xf3, tao comeback li\u1ec1n.","M\xe1u th\u1ea5p nh\u01b0ng tinh th\u1ea7n cao.","G\u1ea7n toang nh\u01b0ng ch\u01b0a toang h\u1eb3n.","\u0110ang \u1edf ng\u01b0\u1ee1ng c\u1eeda sinh t\u1eed \u0111\xf3.","Ch\u1ec9 c\u1ea7n 1 nh\u1ecbp n\u1eefa th\xf4i.","Game ch\u01b0a k\u1ebft th\xfac \u0111\xe2u.","Tao ch\u01b0a ch\u1ebft \u0111\u01b0\u1ee3c \u0111\xe2u.","\u0110\u1eebng c\xf3 v\u1ed9i k\u1ebft lu\u1eadn.","C\xf2n s\u1ed1ng l\xe0 c\xf2n g\xe2y kh\xf3 ch\u1ecbu.","S\u1eafp ch\u1ebft nh\u01b0ng v\u1eabn \u0111\u1ee7 l\xe1o.","\u0110\u1ee9ng v\u1eefng t\u1edbi gi\xe2y cu\u1ed1i.","M\xe0y ngh\u0129 m\xe0y th\u1eafng r\u1ed3i \xe0?","Sai r\u1ed3i, \u0111\xe2y m\u1edbi l\xe0 l\xfac nguy hi\u1ec3m.","HP th\u1ea5p m\u1edbi l\xe0 l\xfac tao nguy hi\u1ec3m nh\u1ea5t.","C\xe0ng g\u1ea7n ch\u1ebft tao c\xe0ng \u0111i\xean.","\u0110\xe2y m\u1edbi l\xe0 phase th\u1eadt s\u1ef1.","\u0110\u1eebng \u0111\u1ec3 tao s\u1ed1ng s\xf3t.","L\u1ee1 tao s\u1ed1ng l\xe0 m\xe0y h\u1ed1i h\u1eadn \u0111\xf3.","K\u1ebft li\u1ec5u tao \u0111i, kh\xf4ng l\xe0 m\xe0y toang.","C\xf2n ch\u1ea7n ch\u1eeb l\xe0 thua \u0111\xf3.","Ra \u0111\xf2n d\u1ee9t \u0111i\u1ec3m \u0111i, n\u1ebfu kh\xf4ng d\xe1m.","Tao c\xf2n chi\xeau cu\u1ed1i ch\u01b0a x\xe0i.","Ulti v\u1eabn c\xf2n \u0111\xf3 nha.","Ch\u1edd tao b\u1ea5m n\xfat cu\u1ed1i c\xe1i coi.","T\u1edbi l\xfac bung h\u1ebft r\u1ed3i.","\u0110\xe2y l\xe0 \u0111\xf2n quy\u1ebft \u0111\u1ecbnh.","Ch\u1ec9 c\u1ea7n sai m\u1ed9t b\u01b0\u1edbc l\xe0 m\xe0y \u0111i.","M\u1ed9t kho\u1ea3nh kh\u1eafc th\xf4i l\xe0 \u0111\u1ee7.","\u0110\u1eebng c\xf3 run tay nha.","\u0110\xe1nh cho \u0111\xe0ng ho\xe0ng coi.","\u0110\xe2y l\xe0 l\xfac \u0111\u1ecbnh \u0111o\u1ea1t.","H\u01a1i th\u1edf y\u1ebfu r\u1ed3i... nh\u01b0ng ch\u01b0a t\u1eaft.","Ch\u01b0a ph\u1ea3i l\xfac tao n\u1eb1m xu\u1ed1ng.","C\xf2n n\u1ee3 m\xe0y m\u1ed9t \u0111\xf2n.","Tr\u1eadn n\xe0y ch\u01b0a xong \u0111\xe2u.","K\u1ebft th\xfac hay b\u1ecb k\u1ebft th\xfac, ch\u1ecdn \u0111i.","M\xe1u \xedt nh\u01b0ng v\u1eabn \u0111\u1ee7 \u0111\u1ea5m.","Nh\xecn tao y\u1ebfu v\u1eady th\xf4i ch\u1ee9 kh\xf4ng hi\u1ec1n.","Tao v\u1eabn c\xf2n \u0111\u1ee9ng \u0111\xe2y n\xe8.","Ch\u01b0a \u0111\u1ee7 \u0111\u1ec3 h\u1ea1 tao \u0111\xe2u.","C\u1ed1 th\xeam ch\xfat n\u1eefa \u0111i, g\u1ea7n r\u1ed3i \u0111\xf3."],t.s)
