B.a03=s(["Kh\xe1 \u0111\u1ea5y... nh\u01b0ng ch\u01b0a \u0111\u1ee7 k\u1ebft li\u1ec5u ta.","\u0110\xf2n \u0111\xf3 \u0111au th\u1eadt, nh\u01b0ng ta v\u1eabn \u0111\u1ee9ng \u0111\xe2y.","Ng\u01b0\u01a1i v\u1eeba ch\u1ea1m \u0111\u01b0\u1ee3c v\xe0o ta th\xf4i.","Nh\u01b0 g\xe3i ng\u1ee9a cho ta v\u1eady","Ng\u01b0\u01a1i y\u1ebfu x\xecu!","Mu\u1ed7i \u0111\u1ed1t inox h\u1ea3?","Y\u1ebfu c\xf2n hay ra gi\xf3","\xc1 \xe1,...","\xc2y da....","\xdai ch\xe0 ch\xe0...","Ui da, c\u0169ng \u0111au \u0111\xf3 nha.","Tr\xfang r\u1ed3i \u0111\xf3, nh\u01b0ng ch\u01b0a xi nh\xea.","\u0110\xe1nh v\u1eady th\xf4i \xe0?","H\u01a1i r\xe1t t\xed, kh\xf4ng \u0111\xe1ng k\u1ec3.","\u0110\xf2n \u0111\xf3 m\xe0 g\u1ecdi l\xe0 m\u1ea1nh \xe0?","\xca \xea, \u0111au thi\u1ec7t nha, nh\u01b0ng ch\u01b0a \u0111\u1ee7.","Tr\xfang nh\u01b0ng kh\xf4ng th\u1ea5m.","C\xf3 c\u1ea3m gi\xe1c \u0111\xf3, nh\u01b0ng y\u1ebfu qu\xe1.","\u0110\xe1nh ki\u1ec3u n\xe0y ch\u1eafc tao s\u1ed1ng l\xe2u.","T\u0103ng l\u1ef1c l\xean \u0111i coi.","\xc1 \u0111au\u2026 m\xe0 th\xf4i k\u1ec7.","Ui, tr\xfang r\u1ed3i n\xe8\u2026 r\u1ed3i sao n\u1eefa?","\u0110\xe1nh ti\u1ebfp \u0111i, ch\u01b0a th\u1ea5y g\xec.","C\xf3 c\u1ed1 g\u1eafng \u0111\xf3, nh\u01b0ng ch\u01b0a t\u1edbi.","H\u01a1i nh\u1ed9t th\xf4i.","\u1ee6a xong ch\u01b0a?","\u0110\xe1nh xong ch\u01b0a \u0111\u1ec3 tao \u0111\xe1nh l\u1ea1i?","Ch\u01b0a th\u1ea5y s\u1ee3 lu\xf4n \xe1.","\u0110\xf2n \u0111\xf3 t\u01b0\u1edfng g\xec gh\xea l\u1eafm.","Nh\xecn nguy hi\u1ec3m m\xe0 y\u1ebfu x\xecu.","\xc1 \xe1, \u0111au qu\xe1\u2026 \u0111\xf9a th\xf4i.","Ui tr\u1eddi, nh\u1eb9 tay gh\xea.","C\u1ed1 l\xean n\u1eefa \u0111i, g\u1ea7n tr\xfang tao r\u1ed3i \u0111\xf3.","Th\xeam t\xed l\u1ef1c n\u1eefa \u0111i.","\u0110\xe1nh v\u1eady tao bu\u1ed3n \u0111\xf3.","C\u0169ng c\xf3 ti\u1ebfn b\u1ed9\u2026 so v\u1edbi l\xfac n\xe3y.","\u0110\u1ee1 h\u01a1n h\u1ed3i n\xe3y m\u1ed9t ch\xfat.","Nh\u01b0ng v\u1eabn ch\u01b0a \u0111\u1ee7 \u0111\xe2u.","T\u1eadp th\xeam \u0111i r\u1ed3i quay l\u1ea1i.","Ch\u01b0a \u0111\u1ea1t y\xeau c\u1ea7u nha.","Tao c\xf2n \u0111\u1ee9ng \u0111\xe2y n\xe8.","\u0110\xe1nh n\u1eefa \u0111i, tao ch\u1ecbu \u0111\u01b0\u1ee3c.","C\xf2n l\xe2u m\u1edbi g\u1ee5c.","Ch\u01b0a \u0111\u1ee7 \u0111\xf4 \u0111\xe2u.","M\u1ea1nh l\xean n\u1eefa \u0111i!","\xc1!\u2026 r\u1ed3i h\u1ebft.","Ui!\u2026 xong ch\u01b0a?","\u0110au \u0111\xf3\u2026 m\xe0 v\u1eabn \u1ed5n.","Tr\xfang c\xe1i nh\u1eb9 h\u1ec1u.","Kh\xf4ng \u0111\xe1ng k\u1ec3.","\u0110\u1eebng c\xf3 t\u01b0\u1edfng v\u1eady l\xe0 hay.","\u0110\xe1nh v\u1eady m\xe0 c\u0169ng t\u1ef1 tin \xe0?","Tao c\xf2n ch\u01b0a nghi\xeam t\xfac \u0111\xe2u.","\u0110\u1eebng l\xe0m tao th\u1ea5t v\u1ecdng ch\u1ee9.","Ch\u01a1i nghi\xeam t\xfac ch\xfat coi.","R\xe1t nh\u1eb9 th\xf4i.","C\u0169ng g\u1ecdi l\xe0 c\xf3 l\u1ef1c.","Nh\u01b0ng ch\u01b0a l\xe0m tao lung lay.","\u0110\xe1nh v\u1eady ch\u01b0a \u0111\u1ee7 l\xe0m tao ch\xfa \xfd.","C\xf2n xa m\u1edbi h\u1ea1 \u0111\u01b0\u1ee3c tao.","\xca coi ch\u1eebng, tao b\u1eaft \u0111\u1ea7u kh\xf3 ch\u1ecbu r\u1ed3i \u0111\xf3.","\u0110\u1eebng \u0111\u1ec3 tao n\u1ed5i \u0111i\xean.","\u0110\xe1nh ti\u1ebfp l\xe0 tao tr\u1ea3 \u0111\xf2n \u0111\xf3.","Ch\u1ecdc nh\u1ea7m ng\u01b0\u1eddi r\u1ed3i \u0111\xf3.","Gi\u1ee1n v\u1eady \u0111\u1ee7 r\u1ed3i nha."],t.s)
